    int n;

    // Read integer n from input
    scanf("%d", &n);

    // Generate and print each row of the triangle pattern
    for (int i = 1; i <= n; i++) {
        // Print leading spaces to center the digits
        for (int j = 0; j < n - i; j++) {
            printf(" ");
        }

        // Print i digits, repeated i times
        for (int k = 0; k < i; k++) {
